export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteResult {
  premium: number;
}

const PROCESSING_FEE = 5;
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
const FIRST_INSURANCE_SURCHARGE = 0.1;

// Rounds up in MHPCO's favor, guarding against floating-point drift
// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
const roundUpInFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const itemPremium = (item: Item): number => {
  const basePremium = BASE_PREMIUMS[item.type];
  return basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
};

export const quote = (customer: Customer, items: Item[]): QuoteResult => {
  const basePremiumTotal = items.reduce(
    (total, item) => total + itemPremium(item),
    0,
  );
  const exactPremium = basePremiumTotal + PROCESSING_FEE;
  return { premium: roundUpInFavor(exactPremium) };
};

export const claim = (...args: unknown[]): unknown => {
  return undefined;
};

