const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const componentBasePremium = (count: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const loose = count % BLOCK_SIZE;
  return blocks * BLOCK_BASE_PREMIUM + loose * COMPONENT_BASE_PREMIUM;
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const basePremiumTotal = (items: Item[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const count of Object.values(componentCounts)) {
    total += componentBasePremium(count);
  }
  return total;
};

