}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteResult {
  premium: number;
}

const PROCESSING_FEE = 5;
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
const FIRST_INSURANCE_SURCHARGE = 0.1;

// Rounds up in MHPCO's favor, guarding against floating-point drift
// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
const roundUpInFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

// Components of the same type form blocks of BLOCK_SIZE priced at BLOCK_BASE_PREMIUM;
// leftover loose components are priced individually.
const componentGroupBasePremium = (count: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const loose = count % BLOCK_SIZE;
  return blocks * BLOCK_BASE_PREMIUM + loose * COMPONENT_BASE_PREMIUM;
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const countByType = (items: Item[]): Record<string, number> =>
  items.reduce<Record<string, number>>((counts, item) => {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
    return counts;
  }, {});

const sum = (values: number[]): number =>
  values.reduce((running, value) => running + value, 0);

const basePremiumTotal = (items: Item[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const components = items.filter(isComponent);

  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
  const componentsTotal = sum(
    Object.values(countByType(components)).map(componentGroupBasePremium),
  );

  return mainItemsTotal + componentsTotal;
};

export const quote = (customer: Customer, items: Item[]): QuoteResult => {
  const itemsPremiumTotal =
    basePremiumTotal(items) * (1 + FIRST_INSURANCE_SURCHARGE);
  const exactPremium = itemsPremiumTotal + PROCESSING_FEE;
  return { premium: roundUpInFavor(exactPremium) };
};

export const claim = (...args: unknown[]): unknown => {
  return undefined;
};

